// Calcular fechas para el filtro
const today = new Date();
const yesterday = new Date();
yesterday.setDate(today.getDate() - 1);

const fmt = (d) => d.toISOString().split('T')[0];

return [{
  json: {
    fechaDesde: fmt(yesterday),
    fechaHasta: fmt(today),
    label: fmt(yesterday)
  }
}];

// Verificar que GitHub aceptó el dispatch
const statusCode = items[0].json.statusCode;

if (statusCode !== 204) {
  throw new Error(`GitHub dispatch falló. Status: ${statusCode}. Body: ${JSON.stringify(items[0].json.body)}`);
}

return [{
  json: {
    dispatched: true,
    statusCode,
    fechaDesde: $node['Calcular Fechas'].json.fechaDesde,
    fechaHasta: $node['Calcular Fechas'].json.fechaHasta,
    timestamp: new Date().toISOString()
  }
}];

// Procesar resultado que llegó desde GitHub Actions
const body = items[0].json.body || items[0].json;

if (!body.success) {
  throw new Error(`GitHub Actions reportó error: ${body.error}`);
}

return [{
  json: {
    success: true,
    records: body.records,
    filename: body.filename,
    driveUrl: body.driveUrl,
    driveId: body.driveId,
    fechaDesde: body.fechaDesde,
    fechaHasta: body.fechaHasta,
    elapsedSeconds: body.elapsedSeconds,
    completedAt: new Date().toISOString()
  }
}];
